// Parse CSV response from Semrush
const csv = $input.first().json.data || '';
const lines = csv.split('\n').filter(l => l.trim());
if (!lines.length) return [];

const headers = lines[0].split(';').map(h => h.trim());
const keywords = lines.slice(1).map(line => {
  const values = line.split(';');
  const obj = {};
  headers.forEach((h, i) => { obj[h] = values[i]?.trim(); });
  return obj;
}).filter(k => k.Keyword);

// Find declining keywords (drop >= 3 positions)
const declining = keywords
  .map(k => ({
    keyword: k.Keyword,
    url: k.URL || k.Landing_page,
    position: parseInt(k.Position || k.Pos || 100),
    previous: parseInt(k['Prev.Position'] || k.Prev_pos || 100),
    volume: parseInt(k['Search Volume'] || k.Volume || 0),
    delta: parseInt(k.Position || 100) - parseInt(k['Prev.Position'] || 100)
  }))
  .filter(k => k.delta >= 3 && k.volume > 10)
  .sort((a,b) => (b.volume * b.delta) - (a.volume * a.delta))
  .slice(0, 5); // Top 5 most impactful

return declining.map(k => ({ json: k }));

const html = $json.data || '';
// Extract headings
const h1 = [...html.matchAll(/<h1[^>]*>([^<]+)<\/h1>/gi)].map(m => m[1]).join(', ');
const h2s = [...html.matchAll(/<h2[^>]*>([^<]+)<\/h2>/gi)].map(m => m[1]).slice(0,8);
const h3s = [...html.matchAll(/<h3[^>]*>([^<]+)<\/h3>/gi)].map(m => m[1]).slice(0,10);
const word_count = html.replace(/<[^>]*>/g,'').split(/\s+/).length;
const meta_desc = (html.match(/<meta name="description" content="([^"]+)"/) || [])[1] || '';
const title = (html.match(/<title>([^<]+)<\/title>/) || [])[1] || '';

const kw = $('Detect Declines').item.json;
const competitors_raw = $('Fetch SERP Competitors').item.json.data || '';
const comp_urls = [...competitors_raw.matchAll(/https:\/\/[^;\n]+/g)].map(m=>m[0]).slice(0,3);

return { json: { ...kw, h1, h2s, h3s, word_count, meta_desc, title, competitor_urls: comp_urls } };

